window.__QUIZ_DATA__=[{"id":"theory>Agricultural Science>2006>SECTION A>1>a","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"BASIC CONCEPTS : ROLE OF NON-GOVERNMENTAL ORGANIZATIONS IN AGRICULTURAL DEVELOPMENT","question":"State three charateristics of agricultural non-governmenta organisation.","images":[],"marking_scheme":"Characteristics of Agricultural Non-Governmental Organisation :   - They are established by private agendas O or corporate bodies concerned with the development of agriculture all over the world.  - They are not owned controlled by the government.  - They are privately funded.  - Their activities cut across many countries with r specific aims of developing improved species of crops and livestock breeds.  - They are non-profit making.  - They do not pay corporate taxes.","marks":"5","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION A>1>b>i","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC CONCEPTS : ROLE OF NON-GOVERNMENTAL ORGANIZATIONS IN AGRICULTURAL DEVELOPMENT","question":"state five objective of each of the following:    West African rice development agency","images":[],"marking_scheme":"Objectives of West Africa Rice Development Agency:   - To promote the cultivation of rice within the West Africa sub-region.   - To develop rice species with high yield.   - To develop rice species with high quality.   - To produce rice species which can adapt to the climatic condition of West Africa sub-region.  - To develop disease resistant varieties of rice.  - To develop pest resistant varieties of rice.  - To develop rice which can meet the nutritional needs of the West Africa sub-region.","marks":"5","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION A>1>b>ii","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC CONCEPTS : ROLE OF NON-GOVERNMENTAL ORGANIZATIONS IN AGRICULTURAL DEVELOPMENT","question":"state five objective of each of the following:  International institute of tropical agriculture.","images":[],"marking_scheme":"Objectives of International Institute of Tropical Agriculture:   -To promote the cultivation of food crops such as maize, cowpea, cassava, yam and plantain within the tropics.   - To develop high yielding food crops.   - To develop food crops with high quality.   - To develop food crops that are resistant to diseases.   - To develop food crops that can adapt to the climate of tropical countries.  - To encourage the local farmers to grow the crops approved by the institute.  - To improve the methods of processing food crops.  - To improve the utilization methods of food crops.   - To develop appropriate farming systems for the West Africa sub-region.","marks":"5","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION A>1>c","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BASIC CONCEPTS : ROLE OF NON-GOVERNMENTAL ORGANIZATIONS IN AGRICULTURAL DEVELOPMENT","question":"Mention three other non-governmental organisation involved in agricultural development.","images":[],"marking_scheme":"Other Non-governmental Organisation involved in Agricultural Development:   - International Livestock Research Institute/International Livestock Centre for Africa.   - International Crop Research Institute for Semi-Arid Tropics (ICRISAT).   - International Fund for Agricultural Development (IFAD).  - International Centre for Research in Agro-forestry.  - Action Aid   - ECWA Rural Development   - World Vision International   - Catholic Relief Service   - Hunger Project (Ghana)  - Adventist Relief Agency  - Food and Agricultural Organisation","marks":"5","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION A>2>a","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : PRINCIPLES OF FARMSTEAD PLANNING","question":"Define the term farmstead","images":[],"marking_scheme":"Farmstead: This can be defined as farm house and all production and processing structures.","marks":"5","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION A>2>b","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : PRINCIPLES OF FARMSTEAD PLANNING","question":"List four factors to be considered in planning a farmstead.","images":[],"marking_scheme":"Factors to Consider in Planning a Farmstead:   - Topography   - Soil type   - Accessibility   - Health/Hygiene   - Water supply   - Nearness to market   - Drainage.","marks":"5","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION A>2>c","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : PRINCIPLES OF FARMSTEAD PLANNING","question":"Explain the importance of the factor listed in (b).","images":[],"marking_scheme":"Importance of: Topography:    - Living quarters should be located on the highest elevation - to provide good view of the farm.   - Animal quarters to be located far from the living quarters.   - Locate crops such as vegetables on low lying areas where moisture content is high. (iv) Fish ponds are located on slopy grounds.   - Irrigation farms are best sited on flat grounds.   Soil Type:   - Crop farms are sited on soils that are fertile  .- Pastures on less fertile soils.  - Farm building and structures are best located on poor soils.   - Farrn roads are best constructed on well drained poor soil.  Accessibility:   - Locate facilities within walking distance.  - To facilitate the transportation of farm inputs.  - For evacuation of farm produce.   - Good accessibility makes marketing of farm produce possible.  Water Supply:   - Adequate water supply is needed for human and animal use.  - Livestock structures are located close to source of water supply for easy cleaning.   - Water is required for irrigation purposes.  Health/Hygiene:   - Erect livestock units against wind direction.   - Locate animal units far away from the dwelling houses to avoid health hazards.  Nearess to Market:   - Reduces distribution/transport cost.   - Exposes products to many buyers.   - Reduces the need for farm storage facilities.  Drainage   - Adequate drainage is important to avoid water logging.  - Gentle slope facilitates proper drainage.  - Good drainage makes movement easier within the farm.","marks":"5","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION A>2>d","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : PRINCIPLES OF FARMSTEAD PLANNING","question":"Give two reason for planning a farmstead.","images":[],"marking_scheme":"Reasons for Planning Farmstead:   - Allows for proper utilisation of resources without wastage.  - Makes the farmer to be more responsive to market demand.  - Encourages efficiency of farm activities.  - It makes coordination and control of farm operations easier.","marks":"5","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION B>3>a","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"List four asexual method of crop propagation.","images":[],"marking_scheme":"Asexual Methods of Propagaion:   - Budding  - Layering  - Cutting   - Grafting","marks":"4","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION B>3>b>i","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC CONCEPTS : MEANING AND DIFFERENCES BETWEEN SUBSISTENCE AND COMMERCIAL AGRICULTURE","question":"Define the following terms:    mixed farming","images":[],"marking_scheme":"- Mixed Farming: This is a system of farming in which both crops and animals are raised on the same farm or piece of land.","marks":"4","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION B>3>b>ii","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Define the following terms:  inter-cropping","images":[],"marking_scheme":"- Inter Cropping: A practice of growing a minor crop with a major crop on the same piece of land and the minor crop s, harvested before the major crop.","marks":"4","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION B>3>b>iii","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Define the following terms:  ley farming","images":[],"marking_scheme":"- Ley Farming: This is the practice whereby a piece of farmland is alternatively cultivated with pasture crops and food crops.","marks":"4","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION B>3>c","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"State four advantages of each of mixed farming and inter-cropping.","images":[],"marking_scheme":"Advantages of Mixed Farming :   - The farmer is assured of regular income/employment throughout the year.  - The farmer feeds his animals with his crops or waste produce.  - the farmer is assured of protein needs of his family e.g. milk, eggs, meat.  - The faeces and urine of e animals can be used as organic manure.  - It helps to reduce the failure of any single farm enterprise.  - Supply farm power by the animals.  - Optimal/maximal use of land.     Advantages of Inter-cropping :  - Enables some of the crops to serve as ground cover.  - Protects the soil from erosion and harmful effects of sunlight.  - Helps to check the growth of weeds which compete with plants for food.  - Helps the farmer to spread his harvest over the season and so ensure a regular supply of food.   - Reduces the risk of crop failure.  - May reduce the, spread of pests.   - Optimal/maximal use of land.  - May reduce the spread of diseases.   - Source of regular income.   - Planting of legume adds nitrogen to soi","marks":"4","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION B>4>a","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"a","group":"","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"Draw an annotated dagram of a water cycle.","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Agricultural Science>2006>SECTION B>4>b","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"stae six importance of water to crops.","images":[],"marking_scheme":"Importance of Water to Crops :   - used in hydroysing food.   - water dissolves plant nutrients for root absorption.  - used in photosynthesis.  - medium of enzymatic activities.  - large constituent of protoplasm.   - Medium for food nutrients translocation   - transpiration helps to cool plants.   - very vital or sustaining life  - responsible for turgidity of leaves  - needed for seed germination.","marks":"5","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION B>4>c","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"State four ways of conserving water in the soil.","images":[],"marking_scheme":"Ways of Conserving Water in the Soil :     - Stoppage or reduction of surface water run-off.   - Addition of humus/organic manure.  - Removal of weeds to reduce transpiration and water loss.  - mulching   - Cover cropping   - Contour Ridging  - Appropriate tillage  - Strip cropping","marks":"5","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION C>5>a","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"list four ways by which diseases are spread on a crop farm.","images":[],"marking_scheme":"Ways ways By Which Diseases Spread On A Crop Farm :   - rain splash   - use of contaminated tools and equipment.  - use of infected planting materials.   - wind blowing pathogens to other crops.   - animals, especially predators during feeding.  - insect vectors  - visitors  - weeds harbour pathogens  - through irrigation water.","marks":"8","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION C>5>b>i","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"State three symptoms and three control measures of each of the following disases    onion twister","images":[],"marking_scheme":"Symptoms of Onion Twister:   - Twisting and curling of the leaves and the pseudostem.   - The twisted leaves later change from the normal darkgreen colour to yellowish green.   -The neck of the affected onion plant becomes abnormally long.  - the bulbs are narrow and elongated.  - The bulbs rot quickly when stored.   Control Measures of Onion Twister:   - Early Planting  - Removal and and destruction of infected plants.  - By spraying fungicides.  - Practising good farm sanitation.","marks":"6","difficulty":"3"},{"id":"theory>Agricultural Science>2006>SECTION C>5>b>ii","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"State three symptoms and three control measures of each of the following disases  root-knot of tomato","images":[],"marking_scheme":"Symptons of Root-Knot Disease of Tomato :   - Formation of galls or knots on the roots of infected plants  .- Stunted plants.  - The leaves turn yellow.  - Production of many secondary roots.  - Death of plants.   Control Measures of Root-Knot Disease of Tomato:  - Planting resistant varieties of tomatoes.  - Soil treatment with nematicides.   - Soil sterilisation/ burning of crop residue and weeds.  - Practising crop rotation.  - Removal of crop residues from the field.  - Weed control.","marks":"6","difficulty":"3"},{"id":"theory>Agricultural Science>2006>SECTION C>6>a","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Define an insecticides.","images":[],"marking_scheme":"Insecticide: An insecticide is defined as a chemical preparation used to control insect pests.","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION C>6>b","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CROP PROTECTION : PESTS OF CROPS","question":"List four groups of insecticides","images":[],"marking_scheme":"Group of insecticides:   - Powder   - Liquid  - Granules  - Tablets  - Aerosol","marks":"3","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION C>6>c>i","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CROP PROTECTION : PESTS OF CROPS","question":"For each of the following pest, name the class of pesticide used for their control    grasshoppers.","images":[],"marking_scheme":") Class of Pesticide that Kills Specific Insect Pests:  Pest killed\tPesticide \t Pest killed\tPesticide \t(i) Grasshoppers\tInsecticide\t(iii) Weaver birds Rodenticides\tAvicides\t(ii) Rats\tRodenticides\t(iv) Eelworms Avicides\tNematicides","marks":"2","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION C>6>c>ii","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CROP PROTECTION : PESTS OF CROPS","question":"For each of the following pest, name the class of pesticide used for their control  Rats","images":[],"marking_scheme":"Class of Pesticide that Kills Specific Insect Pests:  Pest killed\tPesticide \t Pest killed\tPesticide \t(i) Grasshoppers\tInsecticide\t(iii) Weaver birds Rodenticides\tAvicides\t(ii) Rats\tRodenticides\t(iv) Eelworms Avicides\tNematicides","marks":"2","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION C>6>c>iii","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CROP PROTECTION : PESTS OF CROPS","question":"For each of the following pest, name the class of pesticide used for their control  weaver birds","images":[],"marking_scheme":"Class of Pesticide that Kills Specific Insect Pests:  Pest killed\tPesticide \t Pest killed\tPesticide \t(i) Grasshoppers\tInsecticide\t(iii) Weaver birds Rodenticides\tAvicides\t(ii) Rats\tRodenticides\t(iv) Eelworms Avicides\tNematicides","marks":"2","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION C>6>c>iv","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"CROP PROTECTION : PESTS OF CROPS","question":"For each of the following pest, name the class of pesticide used for their control  eelworms","images":[],"marking_scheme":"Class of Pesticide that Kills Specific Insect Pests:  Pest killed\tPesticide \t Pest killed\tPesticide \t(i) Grasshoppers\tInsecticide\t(iii) Weaver birds Rodenticides\tAvicides\t(ii) Rats\tRodenticides\t(iv) Eelworms Avicides\tNematicides","marks":"2","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION C>6>d>i","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Enumerates two effects of each of the following pest control meaasures on the environment    Chemicals","images":[],"marking_scheme":"Effects of Chemical Control on the Environment:   - Beneficial organism insects like earthworms, bees may be destroyed.  - Some chemicals may be toxic to man, domestic animals and plants.  - It may lead to pollution of the environment.  - It destroys aquatic life.  .","marks":"3","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION C>6>d>ii","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Enumerates two effects of each of the following pest control meaasures on the environment   cultural","images":[],"marking_scheme":"Effects of Cultural Control on the Environment:   - Fire that kills harmful insects may also kill beneficial insects.  - Bush burning spreads within a twinkle of an eye to other places and causing excessive damage to structures, crops and animals.   - Fire destroys organic matter in the soil.  - Tillage operation destroys soil structure and causes erosion","marks":"2","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION C>6>d>iii","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Enumerates two effects of each of the following pest control meaasures on the environment   biological","images":[],"marking_scheme":"Effects of Biological Control on the Environment:   - Natural enemy (organism) introduced to control pest may abandon the pest and start to attack other crops in the environment originally free from attack.   - Predators may feed on other beneficial insects other than the ones intended to control.   -Newly introduced organism may cause imbalance in the ecosystem.   - Breeding for increased yield may alter genetic resistance of crops to pest and diseases thereby leading to increased pest/disease population in the environment.","marks":"3","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION D>7>a","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Explain te term candling in chicks production.","images":[],"marking_scheme":"Candling:   - Candling is the use of a strong shaded light.  - Done to detect unfertilised egg or dead embryo in the egg.  - It is usually carried out during incubation.  - It is carried out first within 6 - 7 days and later 18th -19th days of incubation before hatching of eggs.","marks":"5","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION D>7>b>i","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Write notes on the intensive method of managing poultry under the following headings:    sanitation","images":[],"marking_scheme":"Intensive Poultry Management :     Sanitation:   - Feed only clean diet and water.   -Cull off all sick birds promptly.   -Restrict visitors to farm.  - Avoid keeping different age group of birds together.   -Provide foot bath at the entrance.  - Purchase foundation stock from accredited breeders.  - Vaccinate animals regularly against notificable diseases as and when due.   - Remove and bury of all dead birds promptly.   - Screen windows against wild birds and insects.   - Ensure adequate ventilation of the house.  - Maintain a dry litter if deep litter system is practised.  - Deworm at regular intervals.   - Spray or dust birds at regular intervals against ectoparassites.  - Clean all equipment thoroughly before use.  - Avoid bringing in recycled bags of feed from outside.   - Clear the surrounding bush/weeds around the poultry house.","marks":"5","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION D>7>b>ii","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Write notes on the intensive method of managing poultry under the following headings:  feeding","images":[],"marking_scheme":"Feeding:In terms of cost, feed is the most important input for intensive poultry production, and the availability of low-priced, high-quality feeds is critical for the expansion of the poultry industry. For maximum performance and good health, poultry need a steady supply of energy, protein, essential amino acids, minerals, vitamins and, most important, water. Recent advances in poultry nutrition have focused on three main areas:Developing an understanding of nutrient metabolism and nutrient requirements;determining the availability of nutrients in feed ingredients; and formulating least-cost diets that bring nutrient requirements and nutrient supply together.  Practical poultry diets are formulated from a mixture of ingredients, including cereal grains, cereal by-products, fats, plant protein sources, vitamin and mineral supplements, crystalline amino acids and feed additives. Increasing costs and decreasing supplies of traditional feedstuffs(due in part to food-feed competition and population growth) are expected to affect the future expansion of poultry production. This highlights the urgent need to make greater use of a wide range of alternative feeds(e.g insect meals, food waste, agro-industrial byproducts) and to use fewer human-edible components in poultry diets. The use of most alternative feedstuffs is currently negligible, owing to constraints imposed by nutritional, technical and socio-economic factors. In many circumstances, feed resources are either unused and wasted, or used inefficiently.  A major nutritional problem in developing countries is the biological and chemical contamination of poultry feeds, which may have serious consequences on bird performance and the safety of poultry products for humans. Of the potential contaminants, mycotoxins are the most widespread, particularly in hot, humid conditions, and mycotoxin decontamination must be a part of feeding strategies.","marks":"5","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION D>7>c","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"List six breed of pigs","images":[],"marking_scheme":"Breeds of Pigs:  - West African Dwarf (WAD).  - Large white Landrace Hampshire Duroc  - Large black Wessex Saddle back.   - Tansworth.  - Poland china.  - Chester white. Belgium Pietrain","marks":"5","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION D>8>a","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"a","group":"","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"With the aid of an annoted diagram, describe the life cycle of the liver-fluke( Fasciola hepatica )","images":["data:image/jpeg;base64,"],"marking_scheme":"Liver fluke: The adult fluke is found in the bile duct of animals where it feeds and reproduces. The adult fluke reproduces eggs in the bile duct of the animal which are pass out with faeces from the primary host (Cattle, sheep etc) If the eggs and faeces are passed out by the ruminant into water, they develop to a larva called miracidium which will later hatch ten days later. This larva swims in the water, looks for a snail which is its secondary host (usually Limnea truncatula). It penetrates the snails skin or the pulmonary hole.  It develops to a sporocyst within the snail. Through asexual reproduction the sporocyst reproduces a larva called radial. The radial ruptures from the sporocyst and migrate to the digestive gland of the snail. Here it grows to a final larva called cercaria. After six weeks this cercaria leaves the snail through the pulmonary hole and swims to look for the final host in the water. The cercaria is ingested by the ruminant through infested pasture or water. Then in animal stomach, it makes its way to the animal liver to the bile duct through the liver tissues. It grow to an adult fluke in the animal's bile duct","marks":"10","difficulty":"3"},{"id":"theory>Agricultural Science>2006>SECTION D>8>b","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Explain how to prevent the liver fluke from completing it life cycle in the field","images":[],"marking_scheme":"The life cycle of the fluke can be disrupted by : Eliminating all the snails which are its secondary host in the waters where the ruminant animals drink or feed by spraying copper sulphate solution. Provide clear uninfested waters and feed for the animals. Control weeds along river sides. Periodic burning of pasture to kill eggs in faeces","marks":"5","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION D>8>c","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"List three efffects of lice on animal production","images":[],"marking_scheme":"The Effects of Lice on Animal Production:    - They cause discomfort and irritation on f animals.  - They  blood from animals leading to anaemia.  - They reduce production or yield of animals.   - They create the wounds for secondary infection.   - They transmit diseases.   -They reduce feed and water intake.  - They reduce the growth of animal/cause emaciation.  - Weaken the animals","marks":"5","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION E>9>a","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM RECORDS AND ACCOUNTS","question":"State five reason why farm account are kept","images":[],"marking_scheme":"Reasons why farm accounts are kept by farmers :   - It enables the farmer to know whether he is running the farm at a profit or loss.   - It enables the farmer to make sound management decisions.   - It shows the financial weakness/strength of the farm.   - It enables the farmer to obtain loans from the bank.   - It makes accurate determination of his annual tax possible.   - It enables the farmer to determine the actual worth of his farm for any given purpose.   - For transferring a business from one person to another.   - Facilitates farm auditing.","marks":"5","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION E>9>b>i","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"i","group":"","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM RECORDS AND ACCOUNTS","question":"Using the following information , prepare a profit and  loss account for UNITY FARM, from the year ending December, 2005    (i) Cost of maize seeds  - -D1,400.00     (ii) Cost of fertilizers - D1,200.00    (iii) Cost of insecticides - D1,900.00    (iv) Tractor hiring - D2,000.00    (v) Cost of herbicides - D1,100.00    (vi) Cost of cassava stems - D1,200.00    (vii) Sales of maize - D29,000.00    (viii) Sales of yam - D7,000.00    (ix) Sales of cassava tubers - D5,500.00    (x) Cost of processing cassava tubers - D1,500.00    (xi) Wages of workers - D6,000.00    (xii) Miscellaneous expenses - D4,400.00    (xiii) Maize consumed - D300.00    (xiv) Potato gift to visitors - D1,000.00","images":[],"marking_scheme":"Expenditure (Debit) D\tIncome (Credit)\tD\tCost of maize seeds\t1400.00\tSales of Maize\t29000.00\tCost of fertilizers\t1200.00\tSales of yam\t7000.00\tCost of insecticides\t1900.00\tSales of Cassava tubers\t5500.00\tTractor hiring\t2000.00\tMaize Consumed\t300.00\tCost of herbicides\t1100.00\tPotato gift\t1000.00\tCost of processing cassava tubers\t1500.00\tTotal income\t42800.00\tWages of workers\t6000.00\t \t \tMiscellaneous expenses\t4400.00\t \t \tTotal Expenditure\tD20700.00\t \t \tNet Profit\tD22100.00\t \t \tGrand Total\tD12800.00 \tTotal\tD42800.00\t Alternative 2: Single method   Profit and Loss Account for Unity Farm for the Year ending December, 2005  Sales/Income\t D\tSales of Maize\t29000.00\tSales of yam\t7000.00\tSales of Cassava tubers\t5500.00\tMaize Consumed\t300.00\tPotato gift\t1000.00\tTotal income\tD42800.00\t Less Expenses \t \tCost of Maize\t1400.00\tCost of fertlizers\t1200.00\tCost of insecticides\t1900.00\tTractor hiring\t2000.00\tCost of herbicides\t1100.00\tCost of processing cassava tubers Cost of processing Cassava tubers1200.00 1500.00\tWages of workers6000.00\tMiscellaneous expenses\t4400.00\tTotal Expenditure20700.00Net Profit\t22100.00Grand Total\tD42800","marks":"15","difficulty":"3"},{"id":"theory>Agricultural Science>2006>SECTION E>10>a","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"mention four target group of the extension agent.","images":[],"marking_scheme":"Target Groups of The Extension Agent :   - Commercial farmers.   - Subsistence farmers.  - Farmers' cooperative societies.  - Nomads.   - Youth Organisations e.g. Young Farmers Club.  - Non-governmental organisations.  - Fishermen/ fish farmers.   - Community Development Association.   - Bee keepers.","marks":"7","difficulty":"1"},{"id":"theory>Agricultural Science>2006>SECTION E>10>b","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"Discuss five important quailities of a good extension worker","images":[],"marking_scheme":"Qualities of a Good Extension Worker:   -  Originality : For an extension officer or worker to succeed as an agent of change, he must be original. He must have the native intelligence to be original in his thoughts, words and action.  -  Leadership : He must be a leader among leaders. He must be able to know the way i.e. his goal and lead the rural farmers to grasp and embrace that goal. He must be patient and able to inspire the rural farmers to achieve the goal.  -  Initiative : A good extension worker must have initiative to tackle problems himself before referring them to supervisors. He must be able to take steps without being directed.  -  Organisational Ability : The success of any extension activity will depend on how it is planned, organised and executed. He should be able to organise training of leaders.  -  Problem Solving Ability : A good extension worker must be able to recognise problems, define them in simple terms and solve then if they fall within his training and experience.  -  Clear Judgement : He must possess great foresight, he must be able to appreciate the problems of the farmers on the ground and know what to do to solve them.  -  Reliability Honesty : An extension worker must be reliable, a man of his words. If the agency sends him down to the rural area, he should go down to deliver the piece of information and bring back feedback. If the rural farmers discover that he is reliable, they can then assimilate the new innovation and research findings.  -  Communication Skill : An excellent extension worker must possess good communication skills e.g. good command of local language, boldness and oratory abilities.  -  Freedom from Local Politics : A good extension worker must not be involved in the local politics as as to win the confidence of all members of the target group.  -  Respect for Culture and Traditions : He must be a good mixer for him to succeed. He must be able to come down to their level. He should dress like them, eat whatever they present, possibly drink their water, while not losing his goal for doing all these. By the wise behaviours he will win the hearts of the rural farmers. He should not feel superior to the farmers so as to achieve his goal. He must be approachable.  -  Technical Knowledge : With sound training, an extension worker must be able to impact knowledge. He should be able to motivate these adult learners to acquire knowledge   -  Punctuality and Availability : He should be able to attend all pre-arranged meetings,  seminars, workshops, etc, promptly and always make himself available.","marks":"7","difficulty":"2"},{"id":"theory>Agricultural Science>2006>SECTION E>10>c","subject":"Agricultural Science","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"State four function of an extension worker.","images":[],"marking_scheme":"Functions of an Extension Worker : To change peoples' outlook towards their living conditions.   - To teach rural people to recognise and take interest in their problems so as to overcome them   - To teach farmers improved practices using various methods, demonstrations, lectures, film shows, symposia, radio, etc,  - To act as a link between farmers and research institutes/Government.  - To teach farmers efficient management on the farms.   - To assist in obtaining loans and credits.   - To assist in locating markets for their farm produce,   - To monitor the use of Agric loans.  - To assist farmers tolocate sources of farm input.   - To evaluate the success or otherwise of the extension programme.   - To educate rural women on home management.  - To plan and execute farming educational programmes.","marks":"6","difficulty":"1"}];